from __future__ import annotations

import json
import sys
import warnings
from pathlib import Path

import numpy as np
import pandas as pd
from sklearn.model_selection import StratifiedKFold
from sklearn.metrics import accuracy_score
from sklearn.preprocessing import LabelEncoder
from sklearn.impute import SimpleImputer
from lightgbm import LGBMClassifier
warnings.filterwarnings("ignore")

# ── Config / 配置 ──
DATA_DIR = Path("/Users/justingao/Documents/kagglemate/competitions/titanic/data/raw")
TARGET_COL = "Survived"
ID_COL = "PassengerId"
N_FOLDS = 5
RANDOM_SEED = 42


def main():
    # ── Load data / 加载数据 ──
    train = pd.read_csv(DATA_DIR / "train.csv")
    test = pd.read_csv(DATA_DIR / "test.csv")
    train.columns = train.columns.str.strip()
    test.columns = test.columns.str.strip()

    print(f"[load] train: {train.shape}, test: {test.shape}")

    # ── Separate target and IDs / 分离目标变量和 ID ──
    y = train[TARGET_COL].copy()
    train_ids = train[ID_COL].copy()
    test_ids = test[ID_COL].copy()

    # ── Feature engineering (applied to FULL DataFrames) / 特征工程（在全量 DataFrame 上操作）──
    # No custom feature engineering for heuristic baseline.

    # ── Build feature matrices / 构建特征矩阵 ──
    # Feature columns: both original and newly created by FE / 特征列：原始列 + 特征工程新列
    base_features = [c for c in ["Pclass", "Name", "Sex", "Age", "SibSp", "Parch", "Ticket", "Fare", "Cabin", "Embarked"] if c in train.columns]
    extra_features = [c for c in [] if c in train.columns]
    feature_cols = base_features + extra_features

    # Drop ID and target from features (in case they leaked in) / 从特征中移除 ID 和 target（防止泄露）
    feature_cols = [c for c in feature_cols if c not in (ID_COL, TARGET_COL)]

    X = train[feature_cols].copy()
    X_test = test[feature_cols].copy()

    # ── Preprocessing / 预处理 ──
    # Separate cat/num from LLM-provided hints, filtering to present columns
    # 从 LLM 提示中分离类别/数值特征，过滤到当前存在的列
    _tmpl_cat = ["Name", "Sex", "Cabin", "Ticket", "Embarked"]
    _tmpl_num = ["Pclass", "Parch", "Fare", "Age", "SibSp"]
    categorical_cols = [c for c in _tmpl_cat if c in X.columns]
    numerical_cols = [c for c in _tmpl_num if c in X.columns]

    if numerical_cols:
        num_imputer = SimpleImputer(strategy="median")
        X[numerical_cols] = num_imputer.fit_transform(X[numerical_cols])
        X_test[numerical_cols] = num_imputer.transform(X_test[numerical_cols])

    if categorical_cols:
        cat_imputer = SimpleImputer(strategy="most_frequent")
        X[categorical_cols] = cat_imputer.fit_transform(X[categorical_cols])
        X_test[categorical_cols] = cat_imputer.transform(X_test[categorical_cols])

    for col in categorical_cols:
        le = LabelEncoder()
        combined = pd.concat([X[col], X_test[col]], ignore_index=True).astype(str)
        le.fit(combined)
        X[col] = le.transform(X[col].astype(str))
        X_test[col] = le.transform(X_test[col].astype(str))

    # Drop any remaining non-numeric columns (guard against LLM mistakes)
    # 移除残留的非数值列（防止 LLM 生成的代码出错）
    bad_cols = [c for c in X.columns if X[c].dtype not in (np.int64, np.int32, np.float64, np.float32, bool)]
    if bad_cols:
        print(f"[preprocess] Dropping non-numeric columns / 丢弃非数值列: {bad_cols}")
        X = X.drop(columns=bad_cols)
        X_test = X_test.drop(columns=bad_cols)

    # Ensure test has same columns as train / 确保测试集列与训练集一致
    X_test = X_test[X.columns]

    print(f"[features] {len(feature_cols)} features ready / 特征就绪")

    # ── CV strategy / 交叉验证策略 ──
    folds = StratifiedKFold(n_splits=5, shuffle=True, random_state=42)
    
    oof_preds = np.zeros(len(X))
    test_preds = np.zeros(len(X_test))
    test_probs = np.zeros((len(X_test), y.nunique()))

    params = {
    "n_estimators": 1000,
    "learning_rate": 0.05,
    "num_leaves": 31,
    "random_state": 42,
    "verbose": -1
}

    print(f"[cv] Starting StratifiedKFold with LightGBM / 开始 StratifiedKFold 交叉验证")

    fold_scores = []
    for fold, (train_idx, val_idx) in enumerate(folds.split(X, y)):
        X_tr, X_val = X.iloc[train_idx], X.iloc[val_idx]
        y_tr, y_val = y.iloc[train_idx], y.iloc[val_idx]

        model = LGBMClassifier(**params)
        
        model.fit(X_tr, y_tr)
        oof_preds[val_idx] = model.predict(X_val)
        test_probs += model.predict_proba(X_test) / N_FOLDS
        

        fold_score = accuracy_score(y_val, model.predict(X_val))
        fold_scores.append(fold_score)
        print(f"  fold {fold+1}: ACCURACY={fold_score:.5f}")

    cv_mean = np.mean(fold_scores)
    cv_std = np.std(fold_scores)
    print(f"[cv] Mean ACCURACY / 平均 ACCURACY: {cv_mean:.5f} ± {cv_std:.5f}")

    # ── Save out-of-fold predictions / 保存 OOF 预测 ──
    sub_dir = Path("/Users/justingao/Documents/kagglemate/benchmarks/results/titanic/20260618_071905")
    sub_dir.mkdir(parents=True, exist_ok=True)

    oof_df = pd.DataFrame({
        ID_COL: train_ids,
        "oof_pred": oof_preds,
    })
    oof_path = sub_dir / "oof_pred.csv"
    oof_df.to_csv(oof_path, index=False)
    print(f"[done] OOF predictions saved / OOF 预测已保存 → {oof_path}")

    # ── Submission / 生成提交文件 ──
    
    
    submission = pd.DataFrame({
        ID_COL: test_ids,
        "Survived": test_probs.argmax(axis=1),
    })
    
    
    sub_path = sub_dir / "baseline_lightgbm_001.csv"
    submission.to_csv(sub_path, index=False)
    print(f"[done] Submission saved / 提交文件已保存 → {sub_path}")

    # ── Feature importance / 特征重要性 ──
    try:
        importances = model.feature_importances_
        top_features = sorted(zip(X.columns, importances), key=lambda x: -x[1])[:20]
        print("[features] Top 10 / 特征重要性 Top 10:")
        for name, imp in top_features[:10]:
            print(f"  {name}: {imp:.4f}")
    except Exception:
        top_features = []

    # ── Structured output (parsed by KaggleMate) / 结构化输出（由 KaggleMate 解析）──
    print("=== RESULTS ===")
    print(json.dumps({
        "model": "LightGBM",
        "cv_score": float(cv_mean),
        "cv_std": float(cv_std),
        "cv_folds": N_FOLDS,
        "metric": "ACCURACY",
        "features": list(X.columns),
        "fold_scores": [float(s) for s in fold_scores],
        "feature_importance": [(str(name), float(imp)) for name, imp in top_features[:10]],
        "submission_path": str(sub_path),
        "oof_path": str(oof_path),
        "config_path": "/Users/justingao/Documents/kagglemate/benchmarks/results/titanic/20260618_071905/experiment_config.json",
        "cv_plan_summary": "StratifiedKFold (n_splits=5)",
    }, indent=2))


if __name__ == "__main__":
    main()